let rawText = item.json.text || '';
let isViolated = false;
let violations = [];

// Regex matching
const ccPattern = /\b(?:4[0-9]{12}(?:[0-9]{3})?|5[1-5][0-9]{14}|3[47][0-9]{13}|3(?:0[0-5]|[68][0-9])[0-9]{11}|6011[0-9]{12}|(?:2131|1800|35\d{3})\d{11})\b/;
const ssnPattern = /\b\d{3}-\d{2}-\d{4}\b/;
const secretPattern = /(?i)(key|secret|password|token|auth|credential|jwt)\b\s*[:=]\s*["']?[a-zA-Z0-9_\-\.\/]{20,}["']?/;

if (ccPattern.test(rawText)) {
  rawText = rawText.replace(ccPattern, '[MASKED_PII_CC]');
  violations.push('Credit Card leak detected and scrubbed');
}

if (ssnPattern.test(rawText)) {
  rawText = rawText.replace(ssnPattern, '[MASKED_PII_SSN]');
  violations.push('SSN leak detected and scrubbed');
}

if (secretPattern.test(rawText)) {
  isViolated = true;
  violations.push('Raw API key or Secret credential found - BLOCKING REQUEST');
}

return {
  action: isViolated ? 'Blocked' : 'Proceed',
  scrubbed_payload: rawText,
  violations_detected: violations
};
